const allItems = $input.all();
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 2);

function getMediaName(url, rawSource, summary) {
  const clean = (s) => s && s !== 'Unknown' && s !== 'unknown' && s.trim() !== '';
  if (clean(rawSource)) return rawSource;

  // 既知ドメインのペア（new URL()を使わず文字列マッチ）
  const pairs = [
    ['techcrunch.com','TechCrunch'],['wired.com','Wired'],['reuters.com','Reuters'],
    ['bloomberg.com','Bloomberg'],['theverge.com','The Verge'],['venturebeat.com','VentureBeat'],
    ['arstechnica.com','Ars Technica'],['zdnet.com','ZDNet'],['engadget.com','Engadget'],
    ['thenextweb.com','The Next Web'],['businessinsider.com','Business Insider'],
    ['forbes.com','Forbes'],['wsj.com','Wall Street Journal'],
    ['nytimes.com','New York Times'],['washingtonpost.com','Washington Post'],
    ['ft.com','Financial Times'],['openai.com','OpenAI'],['anthropic.com','Anthropic'],
    ['microsoft.com','Microsoft'],['apple.com','Apple'],['nvidia.com','NVIDIA'],
    ['mit.edu','MIT Technology Review'],['ieee.org','IEEE Spectrum']
  ];

  // URL文字列に既知ドメインが含まれるか（エンコードURL対応）
  const urlL = (url || '').toLowerCase();
  for (const [domain, name] of pairs) {
    if (urlL.includes(domain)) return name;
  }

  // summaryにドメインが含まれるか（Google News RSS対応）
  const sumL = (summary || '').toLowerCase();
  for (const [domain, name] of pairs) {
    if (sumL.includes(domain)) return name;
  }

  // 単純なregexでホスト名抽出
  const m = urlL.match(/https?:\/\/(?:www\.)?([^\/\s?#]+)/);
  if (m) {
    const host = m[1];
    if (host.includes('google.com')) return 'Google News';
    const base = host.split('.')[0];
    return base.charAt(0).toUpperCase() + base.slice(1);
  }

  return 'Unknown';
}

function isNonTargetLanguage(text) {
  const korean = (text.match(/[\uAC00-\uD7AF]/g) || []).length;
  const arabic = (text.match(/[\u0600-\u06FF]/g) || []).length;
  return korean > 3 || arabic > 3;
}

const seen = new Set();
const result = [];

for (const item of allItems) {
  const d = item.json;
  const title = d.title || d.headline || '';
  const url = d.link || d.url || d.guid || '';
  const pubDateRaw = d.pubDate || d.isoDate || d.date || d.original_pubDate || '';
  const summary = d.summary || d.description || d.content || d.contentSnippet || '';

  if (!title || !url) continue;
  if (isNonTargetLanguage(title)) continue;

  const key = title.substring(0, 30).toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  let pubDate = null;
  try { pubDate = pubDateRaw ? new Date(pubDateRaw) : null; } catch(e) {}
  if (pubDate && pubDate < cutoff) continue;

  const source_media = getMediaName(url, d.source || d.Source || d.feedTitle || '', summary);

  result.push({ json: {
    title,
    url,
    pubDate: pubDateRaw,
    summary,
    source_media
  }});
}

return result;

// AIキーワードフィルター（タイトル+サマリーチェック）
const AI_REGEX    = /\bai\b|artificial intelligence|openai|chatgpt|claude|gemini|anthropic|generative|genai|\bllm\b|large language model|deep learning|machine learning|neural network|copilot|\bgpt[-\s]?[0-9o]/i;
const AI_REGEX_JA = /人工知能|機械学習|生成[Aa][Ii]|大規模言語モデル|ディープラーニング|深層学習/;
const EXCLUDE_REGEX = /spring sale|prime day|black friday|cyber monday|best deal|\bdiscount\b|\bpromo\b|\bcoupon\b|セール|割引/i;

const allItems = $input.all();
if (allItems.length === 0) throw new Error('ニュースが0件です');

// フィルタリング：AIキーワードを含み、除外ワードを含まないもののみ通過
const filtered = allItems.filter(item => {
  const t = (item.json.title || '') + ' ' + (item.json.summary || '');
  if (EXCLUDE_REGEX.test(t)) return false;
  return AI_REGEX.test(t) || AI_REGEX_JA.test(t);
});

if (filtered.length < 5) {
  throw new Error(`AI関連ニュースが${filtered.length}本しかありません（5本必要）`);
}

// ソースごとにグループ化してラウンドロビン選択
const bySource = {};
for (const item of filtered) {
  const source = item.json.source_media || 'Unknown';
  if (!bySource[source]) bySource[source] = [];
  bySource[source].push(item);
}

const selected = [];
const sources = Object.keys(bySource);
let round = 0;
while (selected.length < 5) {
  let added = false;
  for (const src of sources) {
    if (selected.length >= 5) break;
    if (bySource[src].length > round) {
      selected.push(bySource[src][round]);
      added = true;
    }
  }
  if (!added) break;
  round++;
}

if (selected.length < 5) {
  throw new Error(`ニュースが${selected.length}本しか取得できなかったため停止（5本必要）`);
}

// ===== 重複ニュース除去（同一ニュースを別メディアが報じた場合の排除）=====
function titleJaccard(t1, t2) {
  const stopWords = new Set(['が','の','を','に','で','と','は','も','a','an','the','to','in','of','and','for','by','on','at']);
  const tokenize = t => {
    const words = t.toLowerCase().replace(/[^a-zA-Z0-9\u3040-\u9FFF\u30A0-\u30FF\u4E00-\u9FFF]/g, ' ').split(/\s+/).filter(w => w.length > 1 && !stopWords.has(w));
    return new Set(words);
  };
  const s1 = tokenize(t1), s2 = tokenize(t2);
  const intersection = [...s1].filter(w => s2.has(w)).length;
  const union = new Set([...s1, ...s2]).size;
  return union > 0 ? intersection / union : 0;
}

const deduped = [];
for (const art of selected) {
  const key = art.title || art.japanese_headline || '';
  const isDup = deduped.some(a => titleJaccard(a.title || a.japanese_headline || '', key) > 0.35);
  if (!isDup) deduped.push(art);
}

// 重複除去後5本未満なら残りfilteredから補充
if (deduped.length < 5) {
  for (const art of filtered) {
    if (deduped.length >= 5) break;
    const key = art.title || '';
    const isDup = deduped.some(a => titleJaccard(a.title || '', key) > 0.35);
    if (!isDup) deduped.push(art);
  }
}

if (deduped.length < 4) {
  throw new Error(`重複除去後もニュースが${deduped.length}本しかありません`);
}

return deduped;

const items = $input.all();
if (items.length < 5) {
  throw new Error(`ニュースが${items.length}本しか取得できなかったため停止（5本必要）`);
}
return items;

