={{ (() => {
  const title   = $json.title        || '';
  const source  = $json.source_media || '';
  const date    = $json.pubDate      || '';
  const summary = $json.summary      || '';
  const url     = $json.url          || '';

  // 洞察スタイル（4パターンローテーション）
  const roberPatterns = [
    '【比喩転換型】技術を読者が知っている世界の比喩に変換して説明し、洞察を展開する。',
    '【逆説型】「一般に〜と思われているが、構造的には逆で〜」という発見的洞察を展開する。',
    '【時間軸転換型】「このペースが続くなら2030年には〜」と未来の具体的な場面に落とす。',
    '【構造束ね型】複数の動向を束ねて一つの大きな構造変化として位置づけ、洞察を統合する。'
  ];

  // 糸口スタイル（8パターン・日付偶奇でセットをずらす）
  const itoguchiPatterns = [
    '【逆読み型】「怖い」と感じるこの変化を別の角度から読むと何が見えるか。断言せず、小さな可能性の方向性を示す。',
    '【選択軸型】この変化の中で読者に「どちらを選ぶか」という岐路があるとしたら何か。命令でなく、選択肢の存在を静かに示す。',
    '【問い型】この変化が孕む本質的な問いを1つ立てて読者に投げ返す。答えは出さなくてよい。',
    '【現場視点型】この状況下で、実装・使い方のレベルで既に動いている方向性はあるか。小さくても具体的な手がかりを示す。',
    '【歴史照合型】過去に似た技術革命・産業変化があったとしたら何か。歴史・他業界の経験からこの変化の行き先の手がかりを示す。',
    '【当事者内側型】この変化の中心にいる人間は何を見て何を考えているか。その内側の論理を想像することで見えてくる糸口がある。',
    '【時間差型】「今は怖く見えるが、5年後にこれを振り返ったとき何と言うだろうか」。時間差の視点からこの変化の別の相貌を示す。',
    '【細部照射型】この大きな変化の中に見落とされがちな小さな事実や動きはないか。細部の中にこそ可能性の糸口が潜んでいる。'
  ];

  // 粒度（3パターン・日付×記事番号でずらす）→ 8×3=24通り
  const grainPatterns = [
    '【マクロ】産業・社会全体への影響スケールで語る。',
    '【ミクロ】特定の1人・1社・1シーンに絞って語る。',
    '【メタ】今これを読んでいる読者自身を対象に語る。'
  ];

  // ユーモアスタイル（8パターン・独立ローテーション）
  const humorStyles = [
    '【ブラックユーモア型】権力・資本・制度の矛盾を皮肉で刺す。「笑えるが笑えない」一言で締める。例：「時価総額600億ドルの企業を弱者と呼ぶ感覚を、少し疑った方がいい。」',
    '【数字オチ型】具体的な数字・金額・年号を使ってオチをつける。例：「2030年、企業のAI戦略が『どこの回線を使うか』から始まる日が来るかもしれない。」',
    '【逆説的観察型】「普通はそう思うが、実は構造的に逆」という切り口で一言切る。例：「ゴールポストを動かしているのは、走っていない人たちだ。」',
    '【ミニマリスト型】一行で全てを言い切る。余計な言葉ゼロ。短ければ短いほど切れ味が増す。例：「歴史は繰り返す——今度は光ファイバーの上で。」',
    '【共犯者型】「私たちも当事者だ」という視点から笑い飛ばす。例：「誰が勝っても、私たちはそれに乗るしかない時代が来る。それを、今のうちに知っておいてほしい。」',
    '【問いかけ挑発型】読者に静かな問いを投げる知的な挑発。断言しない。例：「この技術が誰のものになるかで、次の10年が決まる。」',
    '【ホワイトユーモア型】温かく軽い視点で小さな可笑しみを見つける。読者がクスッとする一言。皮肉ではなく柔らかい笑い。',
    '【自虐的観察型】「私たちもその渦中にいる」という共感から入り、当事者として笑い飛ばす。読者が「わかる」と感じる一言。'
  ];

  const idx           = $itemIndex % 4;
  const roberStyle    = roberPatterns[idx];

  const dayShift      = Math.floor(Date.now() / 86400000) % 2;
  const itoguchiIdx   = ($itemIndex * 2 + dayShift) % 8;
  const itoguchiStyle = itoguchiPatterns[itoguchiIdx];

  const grainIdx      = (Math.floor(Date.now() / 86400000) * 3 + $itemIndex) % 3;
  const grainStyle    = grainPatterns[grainIdx];

  const humorIdx      = (Math.floor(Date.now() / 86400000) * 7 + $itemIndex * 4) % 8;
  const humorStyle    = humorStyles[humorIdx];

  const prompt = `あなたはAI Survival Reportの編集記者だ。JSONのみで回答せよ（\`\`\`不要）。

【最重要・文字数制限（超えたら全体が失敗）】
・fact_summary: 350〜420字（短すぎても失敗・日本語で数えて）
・editorial_eye: 250字以内

【文体ルール：ワンパターン禁止・語彙力豊かな語り部であれ】
・同一記事内で同じフレーズ・同じ構文を2回以上使わない
・以下は繰り返しが禁止（使うこと自体は禁止ではない）：
  「〜がそこにある」「〜を問われている」「誰も口にしない〜」「浮き彫り」「〜を示している」
・語彙が豊かで、読むたびに表現が新鮮な語り部であること
・「書き慣れた記者の文体」を意識する。AIが書いた感を出さない

【絶対ルール】
1. URLは入力のURLをそのままコピー（変更・創作禁止）
2. 固有名詞・数字は原文のまま（推測で異なる固有名詞を作ることは絶対禁止）
3. メディア名は入力のものをそのまま使用
4. fact_summaryは「${source}によると、」で開始
5. 入力データの事実のみ使用（知識補完・創作・推測禁止）
6. 英語の固有名詞・機関名・法律名は必ず日本語訳を括弧で添えること（例: injunction → 差し止め命令（injunction＝裁判所が行動を止める法的ブレーキ）、Pentagon → 米国防総省）
7. 専門用語・略語は「池上彰スタイル」で解説（括弧内に「＝〜のこと」形式。中学生でもわかる言葉で）
8. 元記事のメインテーマと無関係の情報を書かないこと（ページ下部の別記事・広告・リンク記事の内容は使わない）
9. 「不明」「明確ではない」「推測」等の不確実表現は使わない。書けることだけ書く。
10. 禁止表現：「この一週間に報じられた」「〜すべき」「〜になれ」等の命令形

【入力データ】
タイトル: ${title}
メディア名: ${source}
配信日: ${date}
要約: ${summary}
URL: ${url}

【fact_summary（350〜420字・だ・である調・5W1H）】
「${source}によると、」で始める。誰が何をいつどこでなぜどうしたかを簡潔に書く。
専門用語には池上彰スタイルの括弧補足を入れる。不確実なことは書かない。350字未満または420字超は失敗。

【editorial_eye（300字以内・だ・である調）】
3段構成で合計300字以内：
①現実（50-80字）：この変化が読者の現場・社会に何をもたらしているか。正直に、重さも含めて書く。「いい子ちゃん」的表現禁止。
②洞察（120-180字）：${roberStyle}核心に踏み込み、表面的な事実の奥にある構造や矛盾を深く掘り下げる。本音で書け。
③糸口（40-60字）：${itoguchiStyle}${grainStyle}

【ユーモア指示（editorial_eyeのどこか一箇所に自然に織り込む）】
${humorStyle}
毎回同じパターンのユーモアは使わない。比喩を使う場合は「魔法」「お姫様」「勇者」等の幼稚な比喩禁止。知性と切れ味を優先する。

【理想の編集長の眼の実例（このレベルを目指せ）】
・「快挙だ。だが正直に言う。私はこれを手放しで喜べない。時価総額600億ドルの企業を『弱者』と呼ぶ感覚を、少し疑った方がいい。誰が勝っても、私たちはそれに乗るしかない時代が来る。」
・「ゴールポストを動かしているのは、走っていない人たちだ。それが今は機能している。だが次のラウンドは、もっと静かな場所で始まる。」
・「歴史は繰り返す——今度は光ファイバーの上で。」

ラベル不要。箇条書き禁止。命令形禁止。250字超えたら失敗。

【出力JSONのみ】
{"japanese_headline":"固有名詞・数字入り日本語見出し20-35字","original_title":"英語タイトルそのままコピー","fact_summary":"${source}によると...350〜550字","editorial_eye":"300字以内・だ・である調","url":"${url}","source_media":"${source}","pubDate":"${date}"}`;

  return JSON.stringify({
    contents: [{role:'user', parts:[{text: prompt}]}],
    generationConfig: {temperature: 0.5, maxOutputTokens: 16384}
  });
})() }}

