function extractGeminiText(resp) {
  if (!resp) return '';
  if (resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts) {
    return resp.candidates[0].content.parts[0].text || '';
  }
  return resp.text || '';
}

const leadResp = $('リード＋総括 LLM Chain').first().json;
const titleResp = $('タイトル生成 LLM Chain').first().json;

const leadRawStr = extractGeminiText(leadResp);
const titleText = extractGeminiText(titleResp).trim().replace(/^["「]|["」]$/g, '').split('\n')[0].trim();

let leadJson;
try {
  const cleaned = leadRawStr.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  leadJson = JSON.parse(cleaned);
} catch(e) { leadJson = {lead:'', closing:''}; }


// closingを1400字以内に収める（文章境界で切る）
function truncateAtSentence(text, maxLen) {
  if (!text || text.length <= maxLen) return text;
  const cut = text.substring(0, maxLen);
  const lastPeriod = Math.max(cut.lastIndexOf('。'), cut.lastIndexOf('．'), cut.lastIndexOf('\n\n'));
  return lastPeriod > maxLen * 0.5 ? cut.substring(0, lastPeriod + 1) : cut;
}
const lead = leadJson.lead || '';
const closingRaw = truncateAtSentence(leadJson.closing || '', 1400);
// LLMが総括ヘッダーを含む場合は除去（最終組立Codeで追加するため二重防止）
const closing = closingRaw.replace(/^###?\s*総括[：:][^\n]*\n+/m, '').trim();
const newsBody = $('記事本文組立Code').first().json.news_body || '';
const newsData = $('記事本文組立Code').first().json.news_data || [];

const nl = '\n';
const finalArticle = [
  '# ' + titleText,
  '',
  lead,
  '',
  newsBody,
  '## ◆ 総括：時代の濁流を読み解く',
  '',
  closing,
  ''
].join(nl);

const now = new Date();
// JST = UTC + 9h
const jstNow = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const dateStr = String(jstNow.getUTCFullYear())
  + String(jstNow.getUTCMonth()+1).padStart(2,'0')
  + String(jstNow.getUTCDate()).padStart(2,'0')
  + '-'
  + String(jstNow.getUTCHours()).padStart(2,'0')
  + String(jstNow.getUTCMinutes()).padStart(2,'0')
  + String(jstNow.getUTCSeconds()).padStart(2,'0');

return [{
  json: {
    final_article: finalArticle,
    final_title: titleText,
    lead_text: lead,
    closing_text: closing,
    news_data: newsData,
    slug: dateStr,
    publishDate: jstNow.toISOString()
  }
}];

const data = $input.first().json;
const title = data.final_title || '';
const closingText = data.closing_text || '';
const newsData = data.news_data || [];

const GEMINI_KEY = 'AIzaSyASQDhbyHlJUz1kzCTU5nZCmOet9_9pd9Q';
const GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${GEMINI_KEY}`;

const jstNow = new Date(new Date().getTime() + 9 * 60 * 60 * 1000);
const dayOfWeek = jstNow.getUTCDay();

// ========================================
// MOEBIUS共通ベース（禁止ワード削除済み・v2修正版）
// ========================================
const MOEBIUS_BASE =
  'Moebius bande dessinee panel, ligne claire black ink outlines, detailed crosshatching, ' +
  'transparent watercolor wash, editorial illustration, no text no numbers';

// ========================================
// COMPOSITION: 構図バリエーション（9種）
// ========================================
const COMPOSITION = {
  A: "wide panoramic landscape, vast environment, small human presence in distance",
  B: "aerial bird's eye view looking down from above, overhead perspective, figures seen from high altitude",
  C: "extreme close-up shot, detailed texture in foreground, machinery or technology detail, no wide landscape",
  D: "dawn or sunrise sky filling upper half of frame, atmospheric light rays, horizon line visible, expansive sky",
  E: "multiple human figures in foreground, faces and expressions visible, collaborative scene, warm human-scale environment",
  F: "abstract geometric patterns, glowing data network visualization, colorful node connections, no human figures"
};

// ========================================
// LIGHTING: 光量バリエーション
// ========================================
const LIGHTING = {
  BRIGHT: "golden hour morning light, warm dawn rays, hopeful luminous atmosphere, soft warm sunlight",
  MID:    "warm amber dusk light, golden sunset tones, rich orange and brown palette",
  DARK:   "deep blue night atmosphere, cool moonlight, cinematic dark mood, blue and purple tones"
};

// ========================================
// SLOT_PLAN: スロットごとの構図・光量指定
// ========================================
const SLOT_PLAN = [
  { composition: "D", lighting: "BRIGHT" },  // SLOT_T（cover）
  { composition: "C", lighting: "MID"    },  // SLOT_1（news_0）
  { composition: "B", lighting: "BRIGHT" },  // SLOT_2（news_1）
  { composition: "C", lighting: "DARK"   },  // SLOT_3（news_2）
  { composition: "F", lighting: "MID"    },  // SLOT_4（news_3）
  { composition: "B", lighting: "MID"    },  // SLOT_5（未使用）
  { composition: "D", lighting: "BRIGHT" },  // SLOT_6（未使用）
  { composition: "E", lighting: "MID"    },  // SLOT_7（未使用）
  { composition: "F", lighting: "BRIGHT" },  // SLOT_W（summary）
];

// ========================================
// ネガティブプロンプト（全スロット共通）
// ========================================
const NEGATIVE_PROMPT = "photorealistic, 3d render, anime, cartoon, lone silhouette standing alone in empty landscape, single person tiny in vast empty space, dark brooding atmosphere only, same composition as before, generic AI darkness, server room, data center, server rack, server hall, server towers, computer servers, endless server corridor, glowing server towers, rows of servers";

// ========================================
// buildPrompt: スロットインデックス + シーンテキストからプロンプトを構築
// ========================================
const buildPrompt = (slotIndex, sceneText) => {
  const plan = SLOT_PLAN[slotIndex];
  return [MOEBIUS_BASE, COMPOSITION[plan.composition], LIGHTING[plan.lighting], sceneText].join(", ");
};

// ========================================
// カラーパレット（曜日対応・カバー用）
// ========================================
const COVER_COLOR_MOODS = [
  'midnight navy and pale silver color palette',
  'warm amber and deep cobalt color palette',
  'deep crimson and ivory white color palette',
  'forest green and golden ochre color palette',
  'deep violet and lavender silver color palette',
  'electric cyan and charcoal black color palette',
  'rose gold and slate grey color palette'
];
const colorMood = COVER_COLOR_MOODS[dayOfWeek];

const NEWS_COLORS = [
  'cobalt blue and silver palette',
  'crimson red and warm ivory palette',
  'forest green and golden ochre palette',
  'deep violet and lavender palette'
];

// ブロック/エラーページ判定パターン
const BLOCK_PATTERNS = /cloudflare|403 forbidden|security verification|just a moment|performing security|enable javascript|access denied|ray id:|bot protection|captcha|ddos|challenge page/i;

async function getGeminiScene(promptText, fallback) {
  try {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: GEMINI_URL,
      headers: { 'Content-Type': 'application/json' },
      body: {
        contents: [{ parts: [{ text: promptText }] }],
        generationConfig: { maxOutputTokens: 300, temperature: 0.9 }
      },
      json: true
    });
    const text = (
      resp && resp.candidates && resp.candidates[0] &&
      resp.candidates[0].content && resp.candidates[0].content.parts &&
      resp.candidates[0].content.parts[0] &&
      resp.candidates[0].content.parts[0].text
    ) ? resp.candidates[0].content.parts[0].text.trim() : '';
    if (text && text.length > 20) return text;
    return fallback;
  } catch (e) {
    return fallback;
  }
}

// --- カバー画像シーン生成（SLOT_T = index 0）---
const coverGeminiPrompt =
  'You are writing an image prompt for a Moebius bande dessinee editorial COVER illustration for an AI news report.\n\n' +
  'Based on the issue title and summary below, describe ONE striking visual scene in English (50-70 words) that symbolizes the KEY THEME of this issue.\n\n' +
  'REQUIREMENTS:\n' +
  '1. Dawn or sunrise sky filling upper half of frame — dramatic atmospheric light rays, horizon line visible.\n' +
  '2. Setting must NOT be a beach or sea. Choose from: research lab, server hall, city skyline, factory, control room, space station, etc.\n' +
  '3. Reference the actual AI topics in this issue (AI models, data centers, robots, satellites, etc.).\n' +
  '4. Output ONLY the scene description — no intro, no explanation.\n\n' +
  'Issue title: ' + title + '\n' +
  'Issue summary: ' + closingText.substring(0, 800);

const coverScene = await getGeminiScene(
  coverGeminiPrompt,
  'a researcher standing at floor-to-ceiling windows overlooking a glowing city at dawn, ' +
  'holding a tablet with AI interface, warm sunrise light streaming in, horizon line visible, human-scale perspective'
);
const coverPrompt = buildPrompt(0, colorMood + ', ' + coverScene);

// --- ニュース画像シーン生成（SLOT_1〜4 = index 1〜4）---
const newsItems = newsData.slice(0, 4);
const FALLBACK_SCENES = [
  'a scientist in a bright research lab examining a holographic brain model, warm natural light through large windows, human hands visible',
  'aerial view of a modern city intersection at golden hour, pedestrians and vehicles as tiny figures, urban life in motion',
  'close-up of human hands typing on a keyboard, smartphone screen showing an AI chat interface glowing softly, warm desk lamp light',
  'a judge holding a gavel in a courtroom, scales of justice on the desk, dramatic side-lighting, human expression visible'
];

const scenes = [];
for (let i = 0; i < newsItems.length; i++) {
  const item = newsItems[i];
  const headline = item.japanese_headline || item.original_title || '';
  const rawSummary = item.fact_summary || item.summary || item.body || '';

  const isBlocked = BLOCK_PATTERNS.test(rawSummary) || rawSummary.trim().length < 80;
  const summaryText = isBlocked ? '' : rawSummary.substring(0, 600);

  const slotPlan = SLOT_PLAN[i + 1];
  const compositionHint = COMPOSITION[slotPlan.composition];

  const newsPrompt =
    'You are writing an image prompt for a Moebius bande dessinee editorial illustration.\n\n' +
    'Describe a specific visual scene in English (50-70 words) that visually represents this news article.\n\n' +
    'COMPOSITION REQUIREMENT: ' + compositionHint + '\n\n' +
    'CORE PRINCIPLE: Show the KEY OBJECT, TECHNOLOGY, or CONCEPT itself — not just a generic person.\n\n' +
    'APPROACH:\n' +
    '- Name SPECIFIC objects: robot arm, neural network, smartphone UI, satellite dish, courtroom gavel, server rack, holographic interface, DNA helix, financial chart, etc.\n' +
    '- Match the substance of the news — if it\'s about AI tools, show the tool; if regulation, show scales/documents; if a company, show its product\n' +
    '- Avoid vague "person looking at screen" — show WHAT is on the screen, or show the technology itself\n' +
    '- Output ONLY the scene description.\n\n' +
    (isBlocked
      ? 'Article title: ' + (item.original_title || headline) + '\nSource: ' + (item.source_media || 'tech media')
      : 'Headline: ' + headline + '\nSummary: ' + summaryText
    );

  const scene = await getGeminiScene(newsPrompt, FALLBACK_SCENES[i]);
  scenes.push(scene);
}

// --- 総括画像シーン生成（SLOT_W = index 8）---
const summaryGeminiPrompt =
  'You are writing an image prompt for a Moebius bande dessinee editorial SUMMARY illustration.\n\n' +
  'This image represents the OVERALL TENSION or THEME that runs through all stories in this AI news report.\n\n' +
  'COMPOSITION REQUIREMENT: Abstract geometric patterns, glowing data network visualization, colorful node connections, no human figures.\n\n' +
  'Based on the issue summary, describe ONE striking symbolic visual scene in English (50-70 words).\n\n' +
  'APPROACH:\n' +
  '- Think META: What is the common thread? (AI vs human control, speed of change, ethical crossroads, tech disruption, etc.)\n' +
  '- Use ABSTRACT/NETWORK imagery: glowing data nodes, interconnected AI systems, geometric pattern representing the theme\n' +
  '- Output ONLY the scene description.\n\n' +
  'Issue summary: ' + closingText.substring(0, 1000);

const summaryScene = await getGeminiScene(
  summaryGeminiPrompt,
  'abstract glowing data network visualization, colorful node connections representing AI interconnections, ' +
  'geometric patterns pulsing with electric light, deep space background with constellations of information'
);
const summaryPrompt = buildPrompt(8, summaryScene);

// --- 出力（negative_promptを全スロットに付加）---
const prompts = [
  { type: 'cover', prompt: coverPrompt, negative_prompt: NEGATIVE_PROMPT },
  ...scenes.map((scene, i) => ({
    type: 'news_' + i,
    prompt: buildPrompt(i + 1, NEWS_COLORS[i] + ', ' + scene),
    negative_prompt: NEGATIVE_PROMPT
  })),
  { type: 'summary', prompt: summaryPrompt, negative_prompt: NEGATIVE_PROMPT }
];

return prompts.map(p => ({ json: p }));

const items = $input.all();
// 生成順序: cover → news_0 → news_1 → news_2 → news_3 → summary
const typeOrder = ["cover", "news_0", "news_1", "news_2", "news_3", "summary"];
const urls = {};
items.forEach((item, i) => {
  const type = typeOrder[i] || ("item_" + i);
  const url = item.json.secure_url || item.json.url || "";
  if (url) urls[type] = url;
});
return [{ json: { image_urls: urls } }];

const imageData = $input.first().json;
const articleData = $("最終組立Code").first().json;
let article = articleData.final_article || '';
const urls = imageData.image_urls || {};

// カバー画像：タイトル行直後に挿入
if (urls.cover) {
  article = article.replace(/^(# [^\n]+\n\n)/, '$1![カバー画像](' + urls.cover + ')\n\n');
}

// ニュース画像：「### ◆ タイトル\n\n**配信日」の直前に挿入（順番に差し込む）
for (let i = 0; i < 4; i++) {
  const newsUrl = urls['news_' + i];
  if (newsUrl) {
    article = article.replace(
      /(### ◆ \S[^\n]*\n\n)(\*\*配信日)/,
      '$1![ニュース画像](' + newsUrl + ')\n\n$2'
    );
  }
}

// 総括画像：「## ◆ 総括」の直前に挿入
if (urls.summary) {
  article = article.replace(
    /(## ◆ 総括[^\n]*\n\n)/,
    '![総括画像](' + urls.summary + ')\n\n$1'
  );
}

return [{ json: { ...articleData, final_article: article, image_urls: urls } }];

const data = $input.first().json;
const article = data.final_article || '';
const title = data.final_title || '';
const lead = data.lead_text || '';
const slug = data.slug || '';
const coverUrl = (data.image_urls || {}).cover || (data.image_urls || {}).upload || '';
const publishDate = data.publishDate || new Date().toISOString();
const dateFormatted = publishDate.substring(0, 10) + ' ' + publishDate.substring(11, 16);

const mdx = `---
title: "${title.replace(/"/g, '\\"')}"
lead: "${lead.replace(/"/g, '\\"')}"
date: "${dateFormatted}"
category: "AI"
image: "${coverUrl}"
---

${article}
`;

const encoded = Buffer.from(mdx).toString('base64');

return [{
  json: {
    ...data,
    mdx_content: mdx,
    mdx_base64: encoded,
    github_path: `src/content/blog/${slug}.md`,
    github_message: `feat: AI Survival Report ${dateFormatted}`
  }
}];

const fetchResult = $('blog-posts-data.json取得').first().json;
const currentJson = Buffer.from(fetchResult.content, 'base64').toString('utf-8');
const currentSha = fetchResult.sha;
const existingPosts = JSON.parse(currentJson);

const data = $('GitHub MDX作成Code').first().json;
const title = data.final_title || '';
const lead = data.lead_text || '';
const slug = data.slug || '';
const coverUrl = (data.image_urls || {}).cover || (data.image_urls || {}).upload || '';
const publishDate = data.publishDate || new Date().toISOString();

const newPost = {
  slug: slug,
  title: title,
  lead: lead.substring(0, 200),
  date: publishDate.substring(0, 10),
  category: 'AI',
  image: coverUrl
};

existingPosts.unshift(newPost);
const updatedJson = JSON.stringify(existingPosts, null, 2);
const updatedBase64 = Buffer.from(updatedJson).toString('base64');

return [{ json: { updatedBase64, currentSha, slug } }];

