// ================================================================
// Jina本文取得＋日付検証Code (v2)
// ================================================================
// 【変更理由】
// Vertex AI Grounding（Google検索）は指定URLを実際にフェッチしない。
// タイトルが古い記事と一致すると古い記事の内容を返してしまう。
// Jina Readerは指定URLを実際にHTTPフェッチする。
//
// 【v1→v2変更点】
// - GeminiのPOSTコールを廃止（helpersでのJSONボディ問題を回避）
// - リライトAgentがJina取得テキストを直接受け取る（summaryとして渡す）
// - 同意ページ・ペイウォール検出を追加
// ================================================================

const CUTOFF_MS = 7 * 24 * 60 * 60 * 1000; // 7日
const NOW = Date.now();

const items = $input.all();
const results = [];

// 同意ページ・ペイウォール判定
function isConsentOrPaywallPage(text) {
  const lower = text.toLowerCase();
  const gdprCount  = (lower.match(/gdpr|cookie|consent|privacy policy/g)||[]).length;
  const loginCount = (lower.match(/sign in|subscribe|log in|paywall/g)||[]).length;
  return (gdprCount >= 3 || loginCount >= 3);
}

for (const item of items) {
  const { title, url, source_media, pubDate, summary: rssSummary } = item.json;

  let jinaContent = '';
  let shouldSkip = false;

  // ── Step 1: URLパターンで公開日を即チェック ──
  const urlDateM = url ? url.match(/\/(20\d\d)\/(\d{2})\/(\d{2})\//) : null;
  if (urlDateM) {
    const artDate = new Date(`${urlDateM[1]}-${urlDateM[2]}-${urlDateM[3]}`);
    if (NOW - artDate.getTime() > CUTOFF_MS) {
      console.log('[SKIP:URL-DATE] ' + title + ' → ' + artDate.toISOString().slice(0,10));
      shouldSkip = true;
    }
  }

  // ── Step 2: Jina Reader で本文フェッチ ──
  if (!shouldSkip) {
    try {
      const jinaResp = await helpers.httpRequest({
        method: 'GET',
        url: 'https://r.jina.ai/' + url,
        headers: {
          'Accept': 'text/plain',
          'X-Return-Format': 'markdown',
          'User-Agent': 'Mozilla/5.0 (compatible; NewsBot/1.0)'
        },
        timeout: 25000,
        returnFullResponse: false
      });

      // レスポンス形式を柔軟に処理
      if (typeof jinaResp === 'string') {
        jinaContent = jinaResp;
      } else if (jinaResp && jinaResp.body) {
        jinaContent = String(jinaResp.body);
      } else {
        jinaContent = JSON.stringify(jinaResp);
      }
      jinaContent = jinaContent.slice(0, 4000);

      // ── Step 3: 同意ページ・ペイウォール検出 ──
      if (isConsentOrPaywallPage(jinaContent)) {
        console.log('[FALLBACK:PAYWALL] ' + title + ' → RSS summaryを使用');
        jinaContent = ''; // RSS summaryにフォールバック
      } else {
        // ── Step 4: Jina本文から公開日チェック ──
        const jinaDateM = jinaContent.match(/Published\s*(?:Time)?:\s*(\d{4}-\d{2}-\d{2})/i);
        if (jinaDateM) {
          const artDate = new Date(jinaDateM[1]);
          if (NOW - artDate.getTime() > CUTOFF_MS) {
            console.log('[SKIP:JINA-DATE] ' + title + ' → ' + jinaDateM[1]);
            shouldSkip = true;
            jinaContent = '';
          }
        } else if (!urlDateM) {
          // 年数カウントで古記事を推定（URL・Jinaに明示的な日付がない場合）
          const cnt2024 = (jinaContent.match(/\b2024\b/g)||[]).length;
          const cnt2025 = (jinaContent.match(/\b2025\b/g)||[]).length;
          const cnt2026 = (jinaContent.match(/\b2026\b/g)||[]).length;
          if (cnt2024 >= 5 && cnt2026 === 0 && cnt2025 === 0) {
            console.log('[SKIP:YEAR-COUNT] ' + title + ' → 2024x' + cnt2024);
            shouldSkip = true;
            jinaContent = '';
          }
        }
      }

    } catch(e) {
      console.log('[JINA-ERR] ' + url + ': ' + e.message);
      jinaContent = ''; // Jina失敗 → RSS summaryにフォールバック
    }
  }

  if (shouldSkip) continue;

  // Jina本文が有用であればそれを使用、そうでなければRSS summary
  // リライトAgentはこのsummaryを元に日本語記事を生成する
  const usefulJina = jinaContent.length > 200 && !isConsentOrPaywallPage(jinaContent);
  const finalSummary = (usefulJina ? jinaContent : rssSummary || '').slice(0, 4000);

  results.push({ json: {
    title:        title        || '',
    url:          url          || '',
    source_media: source_media || '',
    pubDate:      pubDate      || '',
    summary:      finalSummary
  }});
}

if (results.length === 0) {
  throw new Error('全記事が古記事と判定されスキップされました。RSSフィードを確認してください。');
}

return results;

