// Fisher-Yatesシャッフル
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// 今回使うフィード：英語5本＋日本語2本
const selectedFeeds = [
  ...shuffle(ALL_FEEDS.english).slice(0, 5),
  ...shuffle(ALL_FEEDS.japanese).slice(0, 2)
];

// XML簡易パーサー
function extractText(block, tags) {
  for (const tag of tags) {
    const m = block.match(new RegExp(`<${tag}[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/${tag}>`, 'i'));
    if (m && m[1]) return m[1].trim();
    // Atom link: <link href="..."/>
    if (tag === 'link') {
      const lm = block.match(/<link[^>]+href="([^"]+)"/i);
      if (lm) return lm[1].trim();
    }
  }
  return '';
}

async function fetchAndParse(feed) {
  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: feed.url,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; RSS Reader)' },
      returnFullResponse: false
    });
    const text = typeof resp === 'string' ? resp : '';
    if (!text) return [];

    const items = [];
    const blockRe = /<item[^>]*>([\s\S]*?)<\/item>|<entry[^>]*>([\s\S]*?)<\/entry>/gi;
    let m;
    while ((m = blockRe.exec(text)) !== null && items.length < 20) {
      const block = m[1] || m[2] || '';
      const title   = extractText(block, ['title']);
      const link    = extractText(block, ['link', 'guid']);
      const pubDate = extractText(block, ['pubDate', 'published', 'updated', 'dc:date']);
      const summary = extractText(block, ['description', 'summary', 'content:encoded', 'content'])
                        .replace(/<[^>]+>/g, '').substring(0, 400);
      if (title && link) {
        items.push({ title, link, pubDate, contentSnippet: summary, source: feed.name });
      }
    }
    return items;
  } catch(e) {
    console.log(`Feed error [${feed.name}]: ${e.message}`);
    return [];
  }
}

// 順次取得
const allItems = [];
for (const feed of selectedFeeds) {
  const items = await fetchAndParse(feed);
  allItems.push(...items);
}

const feedNames = selectedFeeds.map(f => f.name).join(' / ');
console.log(`[RSSシャッフル] 選択: ${feedNames}`);
console.log(`[RSSシャッフル] 合計: ${allItems.length}件`);

// RSS統合コードが$input.all()で受け取れる形式で返す
return allItems.map(item => ({ json: item }));
